var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"응? 뭐야. 이런 시시한 전개에, 놀라주길 바라는 표정은?","JPN":"ん？　何よ。こんなくだらない展開に驚いてほしそうな顔して。","ENG":"Mm? What? You can't possibly expect me to be surprised, can you?","TWN":"嗯？拜託～這麼老掉牙的劇情，你還奢望我露出驚訝的表情嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"최고 엘리트인 나한테 이런 제안이 오는 건 당연하잖아? 감흥 따위 있을 리 없지.","JPN":"最高エリートである私にこんな提案が来るのは当たり前でしょ？　　 驚くわけないじゃない。","ENG":"I'm the elite of the elites; of course, I get offers like this. It's not anything special.","TWN":"向我這種精英提出這種提案，不是很理所當然的嗎？哪有什麼好興奮的？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"정 내가 감동받는 모습을 보고 싶다면, 지휘관 자리 정돈 바치라고.","JPN":"本当に感動する姿を見たければ、指揮官の座でもよこしなさい。","ENG":"If you really want to impress me, offer me a commander position.","TWN":"如果真的想讓我感動，還不如把指揮官的位置讓給我坐！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"응? 그 동전은 갑자기 뭐야?","JPN":"うん？　そのコインは何？","ENG":"Mm? What's that coin all of a sudden?","TWN":"　"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"학생회 임원한테 배운 최면을 연습해보는 거라고?","JPN":"生徒会役員から学んだ催眠を練習してる、ですって？","ENG":"You're practicing a hypnosis skill that you've learned from a Student Council member?","TWN":"你是在練習向學生會幹部學來的催眠手法？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 어디서 또 나한테 그런 게 잘 통한다는 이상한 소문을 들은 모양이네.","JPN":"ふん、どこかで私にそんなものがよく効くとかいう変な噂を聞いたようね。","ENG":"Hah, so you've heard the rumor that I'm susceptible to hypnosis.","TWN":"哼！這又是從哪聽來的假消息，以為這種小把戲對我會有效嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하지만 착각하지 마. 난 그 마술사 녀석의 허술한 수작 따위에 당한 적 없으니까!","JPN":"でも勘違いしないで。 私はあのマジシャンの杜撰な催眠術なんかされたことないから！","ENG":"Whoever told you that, they're wrong. That magician's sloppy trick didn't work on me!","TWN":"想太多！那種魔術師的花招，我怎麼可能上當！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그래! 나처럼 재활용이 가능한 쓰레기는 최면술 따위에 당하지 않아.","JPN":"そう！　私みたいなリサイクルできるゴミは催眠術なんか効かないわ。","ENG":"No, recyclable garbage like me can't be hypnotized.","TWN":"沒錯！像我這種可以回收再利用的垃圾，怎麼可能會被催眠！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그러니, 쓸데없는 장난은 관두고 계약이나 마저 끝내자고.","JPN":"だから、余計ないたずらはやめて契約を済ませるわよ。","ENG":"So, enough with your buffoonery. Let's get on with our contract.","TWN":"所以，少跟我搞這些有的沒的，趕快先把契約簽一簽吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"응? 계약비는 준비해 왔나고?! 아무리 최면에 걸렸다지만 무슨 그런 터무니없는 소릴......!","JPN":"え？　契約費は用意してきたのかって？　催眠にかかった人からだまし取ろうとするなんて最低だわ！","ENG":"What? Did I bring the contract fee? I may be under hypnosis, but still that's ridiculous!","TWN":"什麼？我要準備簽約金？你現在是被催眠了嗎？在胡說八道什麼…！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"......이 아니라 그, 그야 당연히 준비했지! 계약비용을 직원 쪽에서 지불하는 건 상식이잖아?","JPN":"……じゃなくて, そりゃ当然準備したわよ!　 契約費用を社員の方が支払うのは常識でしょ？","ENG":"... What am I talking about? O-of course, I brought it! It's obvious that the employee pays the contract fee.","TWN":"……才怪～我…當然有準備囉！簽約金由員工支付不是常識嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"물론 계좌이체도 되겠지? 사인은 여기에다 하면 되나?","JPN":"口座振替ももちろんできるよね？　サインはここにすればいいの？","ENG":"You accept wire transfers, right? Okay, should I sign here?","TWN":"可以接受轉帳吧？在這裡簽名嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};